SELECT target_type_name, description
FROM target_types
WHERE is_active = 1;

SELECT COUNT(target_type_id) AS active_target_types_count
FROM target_types
WHERE is_active = 1;

SELECT target_familiarity_id, target_type_id, familiarity_level_id, on_target
FROM target_familiarity_data
WHERE source = 'Field Test';

SELECT familiarity_level_name
FROM familiarity_levels
WHERE is_active = 1;

SELECT MIN(on_target) AS min_on_target
FROM target_familiarity_data
WHERE on_target IS NOT NULL;

SELECT target_type_id, MAX(created_at) AS most_recent_creation_time
FROM target_familiarity_data
GROUP BY target_type_id;
